content.text:
Current code:
```typescript
export const nextGeneration = (aliveCells: number[][], steps: number): number[][] => {
  if (steps === 0) return aliveCells;
  return [];
};
```

I need to implement the core Game of Life step logic. The simplest approach: build a set of alive cells, for each alive cell and its neighbors count live neighbors, apply rules, return sorted result.

input.old_string:
export const nextGeneration = (aliveCells: number[][], steps: number): number[][] => {
  if (steps === 0) return aliveCells;
  return [];
};

input.new_string:
export const nextGeneration = (aliveCells: number[][], steps: number): number[][] => {
  if (steps === 0) return aliveCells;

  const aliveSet = new Set(aliveCells.map(([x, y]) => `${x},${y}`));

  const neighborCounts = new Map<string, number>();
  for (const [x, y] of aliveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = `${x + dx},${y + dy}`;
        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      }
    }
  }

  const result: number[][] = [];
  for (const [key, count] of neighborCounts) {
    const [x, y] = key.split(",").map(Number);
    if (aliveSet.has(key) && (count === 2 || count === 3)) {
      result.push([x, y]);
    } else if (!aliveSet.has(key) && count === 3) {
      result.push([x, y]);
    }
  }

  result.sort((a, b) => a[0] - b[0] || a[1] - b[1]);
  return result;
};

