    expect(nextGeneration([[0, 0], [0, 1], [1, 0]], 1)).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
  });
  it.todo("should return alive cells sorted lexicographically by x then y");
  it.todo("should apply rules for multiple generations");
  it.todo("should handle negative coordinates");
});

