  }

  return result;
};

export const nextGeneration = (aliveCells: number[][], steps: number): number[][] => {
  let cells = aliveCells;
  for (let step = 0; step < steps; step++) {
    cells = tick(cells);
  }
  cells.sort((a, b) => a[0] - b[0] || a[1] - b[1]);
